import streamlit as stfrom streamlit_gsheets import GSheetsConnectionimport pandas as pdfrom datetime import datetimeimport urllib.parse# --- 1. SAYFA AYARLARI VE TAM GİZLİLİK ---st.set_page_config(    page_title="Bostanlı Çözüm VIP - Yönetim",     layout="wide",     page_icon="🏫",    initial_sidebar_state="expanded")# Sağ alt "Manage app", sağ üst menü ve tüm Streamlit logolarını GİZLEYEN CSShide_st_style = """            <style>            #MainMenu {visibility: hidden;}            footer {visibility: hidden;}            header {visibility: hidden;}            #stDecoration {display:none;}            [data-testid="stStatusWidget"] {visibility: hidden;}            .stDeployButton {display:none;}            /* Sağ alttaki Manage App yazısını uçurur */            button[title="Manage app"] {display: none !important;}            .viewerBadge_container__1QS1n {display: none !important;}            </style>            """st.markdown(hide_st_style, unsafe_allow_html=True)# --- 2. PRATİK ŞİFRE SİSTEMİ (ENTER İLE ÇALIŞIR) ---def check_password():    if "password_correct" not in st.session_state:        st.title("🔐 Kurumsal Yönetim Paneli")        # on_change kullanarak Enter'a basıldığında tetiklenmesini sağlıyoruz        st.text_input(            "Lütfen Giriş Şifresini Yazın ve Enter'a Basın",             type="password",             key="password_input",            on_change=lambda: st.session_state.update(                {"password_correct": st.session_state.password_input == "cozum35"}            )        )                if "password_correct" in st.session_state and not st.session_state["password_correct"]:            st.error("❌ Hatalı şifre girdiniz.")                    st.info("Bostanlı Çözüm VIP Kurs Merkezi - Yetkisiz erişim yasaktır.")        return False    return Trueif check_password():    # --- 3. GOOGLE SHEETS BAĞLANTISI ---    URL = "https://docs.google.com/spreadsheets/d/18BUCCdmATfgHJB1JkM9-T5lhoUaSXes55iMgHVRpOP4/edit?usp=sharing"    conn = st.connection("gsheets", type=GSheetsConnection)    # --- WHATSAPP FONKSİYONU ---    def whatsapp_link_olustur(tel, mesaj):        tel_str = str(tel).replace(" ", "").replace("-", "").replace("(", "").replace(")", "")        if tel_str.startswith("0"): tel_str = "90" + tel_str[1:]        elif not tel_str.startswith("90"): tel_str = "90" + tel_str        encoded_mesaj = urllib.parse.quote(mesaj)        return f"https://wa.me/{tel_str}?text={encoded_mesaj}"    # --- 4. YAN MENÜ ---    st.sidebar.title("☁️ Çözüm VIP Yönetim")    sayfa = st.sidebar.radio("İşlem Seçiniz:", ["Veli Görüşmeleri", "Kasa İşlemleri", "Kurucu Raporu"])    # --- VELİ GÖRÜŞMELERİ ---    if sayfa == "Veli Görüşmeleri":        st.header("📞 Veli Görüşme Kayıt")        try:            existing_data = conn.read(spreadsheet=URL, worksheet="gorusmeler")        except:            existing_data = pd.DataFrame(columns=["Tarih", "Ad Soyad", "Telefon", "Konu", "Durum", "Notlar"])                with st.form("veli_formu", clear_on_submit=True):            col1, col2 = st.columns(2)            with col1:                v_ad = st.text_input("Veli / Öğrenci Ad Soyad")                v_tel = st.text_input("Telefon Numarası")            with col2:                v_konu = st.selectbox("Konu", ["Yeni Kayıt", "YKS Hazırlık", "LGS Hazırlık", "Rehberlik", "Taksit", "Diğer"])                v_durum = st.selectbox("Durum", ["Beklemede", "Olumlu", "Kayıt Tamamlandı", "İptal"])            v_not = st.text_area("Detaylar")            if st.form_submit_button("Kaydet ve Sayfaya İşle"):                if v_ad and v_tel:                    new_row = pd.DataFrame([{"Tarih": datetime.now().strftime("%Y-%m-%d %H:%M"), "Ad Soyad": v_ad, "Telefon": v_tel, "Konu": v_konu, "Durum": v_durum, "Notlar": v_not}])                    updated_df = pd.concat([existing_data, new_row], ignore_index=True)                    conn.update(spreadsheet=URL, worksheet="gorusmeler", data=updated_df)                    st.success(f"✅ {v_ad} başarıyla kaydedildi!")                    st.markdown(f'<a href="{whatsapp_link_olustur(v_tel, "Sayın " + v_ad + ", görüşmemiz için teşekkür ederiz.")}" target="_blank"><button style="background-color:#25D366;color:white;border:none;padding:12px;border-radius:8px;cursor:pointer;font-weight:bold;">🟢 WhatsApp Mesajı Gönder</button></a>', unsafe_allow_html=True)    # --- KASA İŞLEMLERİ ---    elif sayfa == "Kasa İşlemleri":        st.header("💰 Gelir / Gider Girişi")        try:            existing_kasa = conn.read(spreadsheet=URL, worksheet="kasa")        except:            existing_kasa = pd.DataFrame(columns=["Tarih", "Tip", "Kategori", "Miktar", "Detay"])        with st.form("kasa_formu", clear_on_submit=True):            k_tip = st.radio("İşlem Türü", ["Gelir (Tahsilat)", "Gider (Ödeme)"])            k_kat = st.selectbox("Kategori", ["Kayıt", "Kitap", "Kira", "Maaş", "Fatura", "Reklam", "Diğer"])            k_tutar = st.number_input("Tutar (TL)", min_value=0.0, step=100.0)            k_detay = st.text_input("Açıklama")            if st.form_submit_button("Kasaya İşle"):                new_krow = pd.DataFrame([{"Tarih": datetime.now().strftime("%Y-%m-%d"), "Tip": k_tip, "Kategori": k_kat, "Miktar": k_tutar, "Detay": k_detay}])                updated_kasa = pd.concat([existing_kasa, new_krow], ignore_index=True)                conn.update(spreadsheet=URL, worksheet="kasa", data=updated_kasa)                st.success("💰 Kasa güncellendi.")    # --- KURUCU RAPORU ---    elif sayfa == "Kurucu Raporu":        st.header("📊 Günlük Rapor")        t_str = st.date_input("Tarih Seç", datetime.now()).strftime("%Y-%m-%d")        try:            g_df = conn.read(spreadsheet=URL, worksheet="gorusmeler")            k_df = conn.read(spreadsheet=URL, worksheet="kasa")            g_bugun = g_df[g_df['Tarih'].str.contains(t_str, na=False)]            k_bugun = k_df[k_df['Tarih'] == t_str]            gelir = k_bugun[k_bugun['Tip'] == 'Gelir (Tahsilat)']['Miktar'].sum()            gider = k_bugun[k_bugun['Tip'] == 'Gider (Ödeme)']['Miktar'].sum()            c1, c2, c3 = st.columns(3)            c1.metric("Görüşme", len(g_bugun))            c2.metric("Gelir", f"{gelir:,.0f} TL")            c3.metric("Gider", f"{gider:,.0f} TL")            rapor = f"*📌 BOSTANLI ÇÖZÜM RAPORU ({t_str})*\n\n📞 Görüşme: {len(g_bugun)}\n💰 Gelir: {gelir:,.0f} TL\n💸 Gider: {gider:,.0f} TL\n📈 Net: {gelir-gider:,.0f} TL"            st.info(rapor)            st.markdown(f'<a href="{whatsapp_link_olustur("905492551912", rapor)}" target="_blank"><button style="background-color:#075E54;color:white;border:none;padding:15px;border-radius:10px;cursor:pointer;width:100%;font-weight:bold;">📲 Raporu Kurucuya Gönder</button></a>', unsafe_allow_html=True)        except:            st.error("Veri alınamadı.")